class FileUpload:
    filename: str
    content: bytes
    mime_type: str
    metadata: JSONDict = field(default_factory=dict)


@dataclass(frozen=True)
class ToolRequest:
    name: str
    arguments: JSONDict


@dataclass(frozen=True)
class ModelTurnResult:
    final_text: str | None = None
    tool_requests: list[ToolRequest] = field(default_factory=list)
    reasoning: str | None = None
    provider_request_id: str | None = None
    response_summary: JSONDict | None = None


class Transport(Protocol):
    """Transport adapter boundary for resident and invocation modes."""

"""Deterministic fake model adapter for offline tests."""

from __future__ import annotations

from dataclasses import dataclass
import random
from typing import Any, Iterable, Sequence

from agent_kit.ports import (
    JSONDict,
    ModelTurnResult,
    ProviderError,
    ToolRequest,
)


ScriptItem = ModelTurnResult | JSONDict | BaseException


@dataclass(frozen=True)
class FakeModelStep:
    final_text: str | None = None
    tool_requests: tuple[ToolRequest, ...] = ()
    reasoning: str | None = None
    provider_request_id: str | None = None
    response_summary: JSONDict | None = None

    def to_result(self) -> ModelTurnResult:
        return ModelTurnResult(
            final_text=self.final_text,
            tool_requests=list(self.tool_requests),
            reasoning=self.reasoning,
            provider_request_id=self.provider_request_id,
            response_summary=self.response_summary,
        )


class FakeModel:
    def __init__(
        self,
        *,
        seed: int | str = 0,
        script: Iterable[ScriptItem] | None = None,
    ) -> None:
        self.seed = seed
        self._random = random.Random(str(seed))
        self._script = list(script) if script is not None else None
        self.calls: list[JSONDict] = []
        self.call_count = 0

    def complete_turn(
        self,
        *,
        model_id: str,
        messages: Sequence[JSONDict],
        tools: Sequence[JSONDict],
        hot_context: JSONDict,
        system: str | None = None,
        idempotency_key: str | None = None,
    ) -> ModelTurnResult:
        self.call_count += 1
        self.calls.append(
            {
                "model_id": model_id,
                "system": system,
                "messages": list(messages),
                "tools": list(tools),
                "hot_context": hot_context,
                "idempotency_key": idempotency_key,
            }
        )
        if self._script is None:
            return ModelTurnResult(
                final_text=f"fake reply {self._random.randint(1000, 9999)}",
                reasoning="fake deterministic final response",
                provider_request_id=f"fake_req_{self.call_count}",
                response_summary={"kind": "final"},
            )
        if self.call_count > len(self._script):
            return ModelTurnResult(
                final_text="",
                reasoning="fake script exhausted",
                provider_request_id=f"fake_req_{self.call_count}",
                response_summary={"kind": "exhausted"},
            )
        return _coerce_script_item(
            self._script[self.call_count - 1],
            call_count=self.call_count,
        )


def tool_request(name: str, arguments: JSONDict | None = None) -> ToolRequest:
    return ToolRequest(name=name, arguments=arguments or {})


def provider_error(
    error_details: JSONDict | None = None,
    provider_request_id: str | None = None,
) -> ProviderError:
    return ProviderError(
        error_details=error_details or {"code": "fake_provider_error"},
        provider_request_id=provider_request_id,
    )


def _coerce_script_item(item: ScriptItem, *, call_count: int) -> ModelTurnResult:
    if isinstance(item, BaseException):
        raise item
    if isinstance(item, ModelTurnResult):
        return item
    if isinstance(item, FakeModelStep):
        return item.to_result()
    if isinstance(item, dict):
        if "exception" in item:
            exception = item["exception"]
            if isinstance(exception, BaseException):
                raise exception
            raise RuntimeError(str(exception))
        if item.get("provider_error"):
            raise provider_error(
                item.get("error_details"),
                item.get("provider_request_id"),
            )
        if item.get("runtime_error"):
            raise RuntimeError(str(item.get("runtime_error")))
        return ModelTurnResult(
            final_text=item.get("final_text"),
            tool_requests=[
                _coerce_tool_request(tool)
                for tool in item.get("tool_requests", [])
            ],
            reasoning=item.get("reasoning"),
            provider_request_id=item.get(
                "provider_request_id",
                f"fake_req_{call_count}",
            ),
            response_summary=item.get("response_summary"),
        )
    raise TypeError(f"Unsupported fake model script item: {type(item)!r}")


def _coerce_tool_request(value: Any) -> ToolRequest:
    if isinstance(value, ToolRequest):
        return value
    if isinstance(value, dict):
        return ToolRequest(
            name=value["name"],
            arguments=value.get("arguments", {}),
        )
    raise TypeError(f"Unsupported tool request: {type(value)!r}")


__all__ = [
    "FakeModel",
    "FakeModelStep",
    "provider_error",
    "tool_request",
]

def _summarize_hot_context(hot_context: dict) -> dict:
    epic = hot_context.get("epic") or {}
    return {
        "epic_id": epic.get("id"),
        "epic_state": epic.get("state"),
        "recent_message_count": len(hot_context.get("recent_messages", [])),
        "recent_tool_call_count": len(hot_context.get("recent_tool_calls", [])),
        "active_feedback_count": len(hot_context.get("active_feedback", [])),
        "unresolved_observation_count": len(hot_context.get("unresolved_observations", [])),
        "sprint_count": len(hot_context.get("sprints", [])),
        "all_sprints_pending_no_queued": bool(hot_context.get("all_sprints_pending_no_queued")),
    }

"""Minimal invocation-mode communication tools."""

from __future__ import annotations

from typing import Any

from agent_kit.end_of_turn import ensure_reframing_suggestion
from agent_kit.logging import log
from agent_kit.tool_kit import ExternalSpec, ToolContext, register_tool


SEND_MESSAGE_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "required": ["content"],
    "properties": {
        "content": {"type": "string"},
        "attach_files": {
            "type": ["array", "null"],
            "items": {"type": "string"},
        },
    },
}

SET_ACTIVITY_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "required": ["description"],
    "properties": {
        "description": {"type": "string"},
    },
}

DEFER_TO_CALLER_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "required": ["questions"],
    "properties": {
        "questions": {
            "type": "array",
            "items": {"type": "string"},
        },
        "reason": {"type": ["string", "null"]},
    },
}


@register_tool(
    "send_message",
    schema=SEND_MESSAGE_SCHEMA,
    event_kind="tool_call",
    operation_kind="write",
)
def send_message(
    context: ToolContext,
    content: str,
    attach_files: list[str] | None = None,
) -> str:
    del attach_files
    content = ensure_reframing_suggestion(
        content,
        low_score_details=context.metadata.get("low_second_opinion"),
    )
    context.reply_buffer.append(content)
    is_resident = context.transport is not None
    # Resident sends must wait for Discord confirmation before filling the external id.
    message = context.store.create_message(
        epic_id=context.metadata.get("epic_id"),
        direction="outbound",
        content=content,
        bot_turn_id=context.turn_id,
        synthesize_outbound_id=not is_resident,
    )
    if not is_resident:
        return message["discord_message_id"]

    channel_id = str(context.metadata.get("channel_id") or "")
    endpoint = f"POST /channels/{channel_id}/messages"

    def _post_and_update():
        response = context.transport.post_message(channel_id, content)  # type: ignore[union-attr]
        discord_message_id = (
            response.get("discord_message_id")
            or response.get("id")
            or response.get("message_id")
        )
        if discord_message_id is not None:
            context.store.update_message(
                message["id"],
                discord_message_id=str(discord_message_id),
            )
        return (
            str(discord_message_id) if discord_message_id is not None else None,
            response,
        )

    if context.external_queue is None:
        context.external_queue = []
    context.external_queue.append(
        (
            ExternalSpec(
                provider="discord",
                endpoint=endpoint,
                request_summary={
                    "content_preview": content[:100],
                    "channel_id": channel_id,
                    "message_row_id": message["id"],
                },
            ),
            _post_and_update,
        )
    )
    return message["id"]


