def _normalize_result(value: Any) -> JSONDict:
    if value is None:
        return {}
    if isinstance(value, dict):
        return value
    return {"value": value}


def _first_string(*values: Any) -> str | None:
    for value in values:
        if isinstance(value, str):
            return value
    return None


